// ── file-upload-basic ─────────────────────────────
interface UploadFile {
  id: string;
  name: string;
  size: number;
  progress: number;
  failed: boolean;
}

function EvalFileUploadBasic() {
  const [files, setFiles] = useState<UploadFile[]>([]);
  const timers = useRef<Map<string, ReturnType<typeof setInterval>>>(new Map());

  function startProgress(id: string) {
    const timer = setInterval(() => {
      setFiles((prev) => {
        const file = prev.find((f) => f.id === id);
        if (!file || file.progress >= 100) {
          clearInterval(timer);
          timers.current.delete(id);
          return prev;
        }
        return prev.map((f) =>
          f.id === id ? { ...f, progress: Math.min(f.progress + 10, 100) } : f
        );
      });
    }, 300);
    timers.current.set(id, timer);
  }

  function handleDrop(fileList: FileList) {
    const incoming: UploadFile[] = Array.from(fileList).map((file) => ({
      id: crypto.randomUUID(),
      name: file.name,
      size: file.size,
      progress: 0,
      failed: false,
    }));
    setFiles((prev) => [...prev, ...incoming]);
    incoming.forEach((f) => startProgress(f.id));
  }

  function handleDelete(id: string) {
    clearInterval(timers.current.get(id));
    timers.current.delete(id);
    setFiles((prev) => prev.filter((f) => f.id !== id));
  }

  function handleRetry(id: string) {
    setFiles((prev) =>
      prev.map((f) => (f.id === id ? { ...f, progress: 0, failed: false } : f))
    );
    startProgress(id);
  }

  useEffect(() => {
    const t = timers.current;
    return () => { t.forEach(clearInterval); };
  }, []);

  return (
    <FileUpload.Root>
      <FileUpload.DropZone
        hint="PNG, JPG or PDF (max 5 MB)"
        accept="image/*,.pdf"
        maxSize={5 * 1024 * 1024}
        allowsMultiple
        onDropFiles={handleDrop}
      />
      <FileUpload.List>
        {files.map((f) => (
          <FileUpload.ListItemProgressBar
            key={f.id}
            name={f.name}
            size={f.size}
            progress={f.progress}
            failed={f.failed}
            onDelete={() => handleDelete(f.id)}
            onRetry={() => handleRetry(f.id)}
          />
        ))}
      </FileUpload.List>
    </FileUpload.Root>
  );
}

